<?php
 require_once __DIR__ . '/bootstrap.php'; $config = fmLoadRuntimeConfig(__DIR__); define('AUTH_CALLBACK', $config['AUTH_CALLBACK']); define('ALLOWED_IPS', $config['ALLOWED_IPS']); define('CORS_ENABLED', $config['CORS_ENABLED']); define('CORS_ALLOWED_ORIGINS', $config['CORS_ALLOWED_ORIGINS']); define('RATE_LIMIT_ENABLED', $config['RATE_LIMIT_ENABLED']); define('RATE_LIMIT_MAX_REQUESTS', $config['RATE_LIMIT_MAX_REQUESTS']); define('RATE_LIMIT_WINDOW', $config['RATE_LIMIT_WINDOW']); fmRequireRuntimePhp(__DIR__, '../../security/Auth.php'); $auth = new \FilesManager\Auth(); $auth->requireAuth(); define('BASE_PATH', $config['BASE_PATH']); define('FRONTEND_ROOT_PATH', $config['FRONTEND_ROOT_PATH']); define('CACHE_DIR', $config['THUMBNAIL_CACHE_DIR']); define('THUMBNAIL_SIZE', max($config['THUMBNAIL_MAX_WIDTH'], $config['THUMBNAIL_MAX_HEIGHT'])); define('THUMBNAIL_QUALITY', $config['THUMBNAIL_QUALITY']); define('DEBUG', $config['DEBUG']); define('CACHE_DURATION', 2592000); fmRequireRuntimePhp(__DIR__, '../../security/Validator.php'); fmRequireRuntimePhp(__DIR__, '../../features/media/backend/Thumbnail.php'); use FilesManager\Validator; use FilesManager\Thumbnail; function normalizePath(string $path): string { $path = trim($path); $path = str_replace(['\\', '//'], '/', $path); $path = preg_replace('#/+#', '/', $path); if (empty($path)) { return '/'; } $frontendRoot = rtrim(FRONTEND_ROOT_PATH, '/'); if (!empty($frontendRoot) && strpos($path, $frontendRoot) === 0) { $path = substr($path, strlen($frontendRoot)); } if (empty($path)) { return '/'; } if ($path[0] !== '/') { $path = '/' . $path; } return $path; } function sendError(string $message, int $statusCode = 400): void { http_response_code($statusCode); header('Content-Type: application/json'); echo json_encode([ 'success' => false, 'message' => $message, 'error' => $message, ]); exit; } function sendImage(string $filePath, int $cacheDuration = CACHE_DURATION): void { if (!file_exists($filePath)) { sendError('Miniatura não encontrada', 404); } $mime = mime_content_type($filePath); $size = filesize($filePath); $modified = filemtime($filePath); $etag = md5($filePath . $modified); if (isset($_SERVER['HTTP_IF_NONE_MATCH'])) { $clientEtag = trim($_SERVER['HTTP_IF_NONE_MATCH'], '"'); if ($clientEtag === $etag) { http_response_code(304); header('ETag: "' . $etag . '"'); exit; } } if (isset($_SERVER['HTTP_IF_MODIFIED_SINCE'])) { $ifModifiedSince = strtotime($_SERVER['HTTP_IF_MODIFIED_SINCE']); if ($ifModifiedSince >= $modified) { http_response_code(304); header('ETag: "' . $etag . '"'); exit; } } header('Content-Type: ' . $mime); header('Content-Length: ' . $size); header('Last-Modified: ' . gmdate('D, d M Y H:i:s', $modified) . ' GMT'); header('ETag: "' . $etag . '"'); header('Cache-Control: public, max-age=' . $cacheDuration); header('Expires: ' . gmdate('D, d M Y H:i:s', time() + $cacheDuration) . ' GMT'); readfile($filePath); exit; } try { $file = normalizePath($_GET['file'] ?? ''); if (empty($file)) { sendError('Parâmetro file é obrigatório'); } $cacheDuration = isset($_GET['cache_duration']) ? max(0, (int)$_GET['cache_duration']) : CACHE_DURATION; $basePath = BASE_PATH; if (DEBUG) { error_log("[thumbnail.php] file: $file | BASE_PATH: $basePath"); } $fullPath = Validator::validatePath($file, $basePath); if ($fullPath === false || !file_exists($fullPath)) { sendError('Arquivo não encontrado: ' . $file, 404); } $thumbnail = new Thumbnail(CACHE_DIR, THUMBNAIL_SIZE, THUMBNAIL_SIZE, THUMBNAIL_QUALITY); $thumbPath = $thumbnail->generate($fullPath); if ($thumbPath === false) { sendError('Não foi possível gerar miniatura'); } sendImage($thumbPath, $cacheDuration); } catch (\Exception $e) { sendError($e->getMessage()); } 